import React, { useState, useEffect } from 'react';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const UserDashboard = () => {
    const { user } = useAuth();
    const [rides, setRides] = useState([]);
    const [bookings, setBookings] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showBookingModal, setShowBookingModal] = useState(false);
    const [selectedRide, setSelectedRide] = useState(null);
    const [bookingType, setBookingType] = useState('solo');

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [ridesRes, bookingsRes] = await Promise.all([
                api.get('/rides'),
                api.get('/bookings/my-bookings')
            ]);
            setRides(ridesRes.data.data);
            setBookings(bookingsRes.data.data);
        } catch (error) {
            toast.error('Failed to fetch data');
        } finally {
            setLoading(false);
        }
    };

    const handleBookRide = async () => {
        try {
            await api.post('/bookings', {
                rideId: selectedRide._id,
                bookingType,
                numberOfPassengers: 1
            });
            toast.success('Ride booked successfully!');
            setShowBookingModal(false);
            fetchData();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Booking failed');
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-64">
                <div className="text-gray-600">Loading...</div>
            </div>
        );
    }

    return (
        <div className="container mx-auto px-4 py-8">
            <div className="mb-8">
                <h1 className="text-3xl font-bold text-gray-900">Welcome, {user?.name}!</h1>
                <p className="text-gray-600 mt-2">Find and book rides for your daily commute</p>
            </div>

            {/* Available Rides Section */}
            <div className="mb-12">
                <h2 className="text-2xl font-semibold mb-4">Available Rides</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {rides.map((ride) => (
                        <div key={ride._id} className="bg-white rounded-lg shadow-md p-6 hover:shadow-lg transition">
                            <div className="mb-4">
                                <h3 className="text-lg font-semibold">{ride.routeName}</h3>
                                <p className="text-sm text-gray-500">
                                    {new Date(ride.departureTime).toLocaleString()}
                                </p>
                            </div>
                            <div className="space-y-2 mb-4">
                                <p className="text-sm">
                                    <span className="font-medium">From:</span> {ride.pickupLocation.address}
                                </p>
                                <p className="text-sm">
                                    <span className="font-medium">To:</span> {ride.dropLocation.address}
                                </p>
                                <p className="text-sm">
                                    <span className="font-medium">Available Seats:</span> {ride.availableSeats}
                                </p>
                            </div>
                            <div className="flex justify-between items-center">
                                <div>
                                    <p className="text-sm text-gray-600">Solo Fare</p>
                                    <p className="text-xl font-bold text-blue-600">₹{ride.baseFare}</p>
                                </div>
                                <button
                                    onClick={() => {
                                        setSelectedRide(ride);
                                        setShowBookingModal(true);
                                    }}
                                    className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition"
                                >
                                    Book Now
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
                {rides.length === 0 && (
                    <p className="text-gray-500 text-center py-8">No rides available at the moment</p>
                )}
            </div>

            {/* My Bookings Section */}
            <div>
                <h2 className="text-2xl font-semibold mb-4">My Bookings</h2>
                <div className="space-y-4">
                    {bookings.map((booking) => (
                        <div key={booking._id} className="bg-white rounded-lg shadow-md p-6">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="text-lg font-semibold">{booking.ride.routeName}</h3>
                                    <p className="text-sm text-gray-500">
                                        {new Date(booking.ride.departureTime).toLocaleString()}
                                    </p>
                                    <p className="text-sm mt-2">
                                        Status: 
                                        <span className={`ml-2 px-2 py-1 rounded text-xs ${
                                            booking.status === 'confirmed' ? 'bg-green-100 text-green-800' :
                                            booking.status === 'cancelled' ? 'bg-red-100 text-red-800' :
                                            'bg-yellow-100 text-yellow-800'
                                        }`}>
                                            {booking.status}
                                        </span>
                                    </p>
                                </div>
                                <div className="text-right">
                                    <p className="text-sm text-gray-600">Fare</p>
                                    <p className="text-xl font-bold text-blue-600">₹{booking.fare}</p>
                                </div>
                            </div>
                            {booking.status === 'confirmed' && (
                                <div className="mt-4 pt-4 border-t">
                                    <button
                                        onClick={async () => {
                                            try {
                                                await api.put(`/bookings/${booking._id}/cancel`);
                                                toast.success('Booking cancelled');
                                                fetchData();
                                            } catch (error) {
                                                toast.error('Failed to cancel booking');
                                            }
                                        }}
                                        className="text-red-600 hover:text-red-800 text-sm"
                                    >
                                        Cancel Booking
                                    </button>
                                </div>
                            )}
                        </div>
                    ))}
                    {bookings.length === 0 && (
                        <p className="text-gray-500 text-center py-8">No bookings yet</p>
                    )}
                </div>
            </div>

            {/* Booking Modal */}
            {showBookingModal && selectedRide && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4">
                        <h3 className="text-xl font-bold mb-4">Book Your Ride</h3>
                        <div className="mb-4">
                            <p className="text-sm text-gray-600">Route: {selectedRide.routeName}</p>
                            <p className="text-sm text-gray-600">
                                Time: {new Date(selectedRide.departureTime).toLocaleString()}
                            </p>
                        </div>
                        
                        <div className="mb-4">
                            <label className="block text-sm font-medium mb-2">Booking Type</label>
                            <div className="space-y-2">
                                <label className="flex items-center">
                                    <input
                                        type="radio"
                                        value="solo"
                                        checked={bookingType === 'solo'}
                                        onChange={(e) => setBookingType(e.target.value)}
                                        className="mr-2"
                                    />
                                    <span>Solo Ride - ₹{selectedRide.baseFare}</span>
                                </label>
                                <label className="flex items-center">
                                    <input
                                        type="radio"
                                        value="pooled"
                                        checked={bookingType === 'pooled'}
                                        onChange={(e) => setBookingType(e.target.value)}
                                        className="mr-2"
                                    />
                                    <span>Pooled Ride - ₹{Math.round(selectedRide.baseFare / 2)} (Save 50%)</span>
                                </label>
                            </div>
                        </div>
                        
                        <div className="flex justify-end space-x-3">
                            <button
                                onClick={() => setShowBookingModal(false)}
                                className="px-4 py-2 text-gray-600 hover:text-gray-800"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleBookRide}
                                className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                            >
                                Confirm Booking
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default UserDashboard;
